// Sensing components
instance LiDARSensor : DTDFVocab:SensingComponent [
    base:desc "LiDAR sensor capturing raw point cloud data represented as individual points on a 2D plane"
    DTDFVocab:producedData LiDARRawDataTransmitted
]

instance VehicleStateSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor capturing vehicle state information transmitted from the vehicle"
    DTDFVocab:producedData VehicleStateDataTransmitted
]

instance MotorActuationSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor capturing motor actuation state information from the vehicle"
    DTDFVocab:producedData MotorActuationDataTransmitted
]

instance SteeringServoStateSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor capturing steering servo state information from the vehicle"
    DTDFVocab:producedData SteeringServoStateDataTransmitted
]

// Data transmitted instances
instance LiDARRawDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom LiDARSensor
]

instance VehicleStateDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleStateSensor
]

instance MotorActuationDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorActuationSensor
]

instance SteeringServoStateDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringServoStateSensor
]

// Data instances
instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "LiDAR point cloud data after serialization and unit conversion"
    DTDFVocab:inputTo DataMonitoringEnabler
    DTDFVocab:fromData LiDARRawDataTransmitted
]

instance VehicleStateData : DTDFVocab:Data [
    base:desc "Vehicle state information after transformation into a human-interpretable format"
    DTDFVocab:inputTo DataMonitoringEnabler
    DTDFVocab:inputTo ACCProcessingEnabler
    DTDFVocab:fromData VehicleStateDataTransmitted
]

instance MotorActuationData : DTDFVocab:Data [
    base:desc "Motor actuation state data after transformation"
    DTDFVocab:inputTo ACCProcessingEnabler
    DTDFVocab:fromData MotorActuationDataTransmitted
]

instance SteeringServoStateData : DTDFVocab:Data [
    base:desc "Steering servo state data after transformation"
    DTDFVocab:fromData SteeringServoStateDataTransmitted
]

// Enablers
instance DataMonitoringEnabler : DTDFVocab:Enabler [
    base:desc "Component that processes vehicle state and LiDAR point cloud data for real-time monitoring"
    DTDFVocab:enables DataMonitoringService
]

instance ACCProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Component that receives vehicle state data, computes desired speed for ACC, and sends command back to the vehicle"
    DTDFVocab:enables ComputationOffloadingService
]

instance RemoteManagementEnabler : DTDFVocab:Enabler [
    base:desc "Component that allows remote operators to enable/disable ACC, set desired speed, and issue emergency braking commands"
