]

instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Service that offloads ACC computation from the vehicle and returns the desired speed command"
    DTDFVocab:provides SendDesiredSpeedCommandAction
]

instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Service that enables remote control of ACC, desired speed, and emergency braking"
    DTDFVocab:provides EnableACCAction, SetDesiredSpeedAction, EmergencyBrakeAction
]

// Insights
instance VehicleStateInsight : DTDFVocab:Insight [
    base:desc "Real-time visualization of vehicle state information"
]

instance ObjectTrackingInsight : DTDFVocab:Insight [
    base:desc "Real-time visualization of detected and tracked objects from LiDAR data"
]

instance DrivingPathInsight : DTDFVocab:Insight [
    base:desc "Real-time visualization of the projected driving path"
]

